1	/**
2	 * Modulation Matrix panel: drag-to-connect UI with SVG cable visualization.
3	 * Source list on left, destination list on right.
4	 * Active routes shown as colored cables with amount controls.
5	 *
6	 * Keyboard flow: Enter on source port starts connection mode,
7	 * Tab to destination port, Enter to confirm. Escape cancels.
8	 */
9	
10	import { useCallback, useEffect, useRef, useState } from "react";
11	import { tokens } from "@ui/tokens/tokens";
12	import {
13	  useModulationStore,
14	  MOD_SOURCE_LABELS,
15	  MOD_DEST_LABELS,
16	} from "@state/synth/modulation-store";
17	import {
18	  MOD_SOURCES,
19	  MOD_DESTINATIONS,
20	  type ModSource,
21	  type ModDestination,
22	} from "@audio/synth/modulation-types";
23	
24	import type { ModRoute } from "@audio/synth/modulation-types";
25	
26	type Props = {
27	  trackId: string;
28	};
29	
30	const EMPTY_ROUTES: readonly ModRoute[] = [];
31	
32	const BORDER = "var(--border)";
33	
34	const LABEL_STYLE: React.CSSProperties = {
35	  fontFamily: tokens.font.mono,
36	  fontSize: tokens.text.xs,
37	  color: tokens.color.gray300,
38	  textTransform: "uppercase",
39	  letterSpacing: "0.1em",
40	};
41	
42	// Cable colors per source (cycle through for visual distinction)
43	const SOURCE_COLORS: Record<ModSource, string> = {
44	  lfo1: tokens.color.blue,
45	  lfo2: tokens.color.pink,
46	  ampEnv: tokens.color.amber,
47	  filterEnv: tokens.color.green,
48	  velocity: tokens.color.orange,
49	  aftertouch: tokens.color.violet,
50	  modWheel: tokens.color.cyan,
51	  pitchBend: tokens.color.hotpink,
52	};
53	
54	const PORT_STYLE: React.CSSProperties = {
55	  width: 12,
56	  height: 12,
57	  borderRadius: "50%",
58	  backgroundColor: tokens.color.gray900,
59	  cursor: "pointer",
60	  flexShrink: 0,
61	  padding: 0,
62	  background: "none",
63	};
64	
65	function Port({
66	  testId,
67	  color,
68	  label,
69	  highlight,
70	  onMouseDown,
71	  onMouseUp,
72	  onKeyAction,
73	}: {
74	  testId: string;
75	  color: string;
76	  label: string;
77	  highlight?: boolean;
78	  onMouseDown?: () => void;
79	  onMouseUp?: () => void;
80	  onKeyAction?: () => void;
81	}): React.JSX.Element {
82	  return (
83	    <button
84	      type="button"
85	      data-testid={testId}
86	      aria-label={label}
87	      onMouseDown={onMouseDown}
88	      onMouseUp={onMouseUp}
89	      onKeyDown={(e) => {
90	        if (e.key === "Enter" && onKeyAction) {
91	          e.preventDefault();
92	          onKeyAction();
93	        }
94	      }}
95	      style={{
96	        ...PORT_STYLE,
97	        border: `2px solid ${color}`,
98	        outline:
99	          highlight === true ? `2px solid ${tokens.color.white}` : undefined,
100	        outlineOffset: 2,
101	      }}
102	    />
103	  );
104	}
105	
106	export function ModulationMatrix({ trackId }: Props): React.JSX.Element {
107	  const routes = useModulationStore(
108	    (s) => s.matrices[trackId]?.routes ?? EMPTY_ROUTES,
109	  );
110	  const initMatrix = useModulationStore((s) => s.initMatrix);
111	  const addRoute = useModulationStore((s) => s.addRoute);
112	  const removeRoute = useModulationStore((s) => s.removeRoute);
113	  const updateAmount = useModulationStore((s) => s.updateRouteAmount);
114	  const toggleBipolar = useModulationStore((s) => s.toggleRouteBipolar);
115	
116	  useEffect(() => {
117	    initMatrix(trackId);
118	  }, [trackId, initMatrix]);
119	
120	  const [dragSource, setDragSource] = useState<ModSource | null>(null);
121	  const [connectingSource, setConnectingSource] = useState<ModSource | null>(
122	    null,
123	  );
124	  const [announcement, setAnnouncement] = useState("");
125	  const containerRef = useRef<HTMLDivElement>(null);
126	
127	  const activeSource = dragSource ?? connectingSource;
128	
129	  const handleSrcMouseDown = useCallback((source: ModSource) => {
130	    setDragSource(source);
131	  }, []);
132	
133	  const handleDestMouseUp = useCallback(
134	    (destination: ModDestination) => {
135	      if (dragSource) {
136	        addRoute(trackId, dragSource, destination);
137	        setDragSource(null);
138	      }
139	    },
140	    [dragSource, trackId, addRoute],
141	  );
142	
143	  const handleGlobalMouseUp = useCallback(() => {
144	    setDragSource(null);
145	  }, []);
146	
147	  // Keyboard: start connecting from source
148	  const handleSrcKeyAction = useCallback(
149	    (source: ModSource) => {
150	      if (connectingSource === source) {
151	        setConnectingSource(null);
152	        setAnnouncement("Connection cancelled.");
153	      } else {
154	        setConnectingSource(source);
155	        setAnnouncement(
156	          `Connecting from ${MOD_SOURCE_LABELS[source]}. Tab to a destination and press Enter to connect.`,
157	        );
158	      }
159	    },
160	    [connectingSource],
161	  );
162	
163	  // Keyboard: complete connection to destination
164	  const handleDestKeyAction = useCallback(
165	    (destination: ModDestination) => {
166	      if (connectingSource) {
167	        addRoute(trackId, connectingSource, destination);
168	        setAnnouncement(
169	          `Connected ${MOD_SOURCE_LABELS[connectingSource]} to ${MOD_DEST_LABELS[destination]}.`,
170	        );
171	        setConnectingSource(null);
172	      }
173	    },
174	    [connectingSource, trackId, addRoute],
175	  );
176	
177	  // Escape cancels keyboard connection
178	  const handleKeyDown = useCallback(
179	    (e: React.KeyboardEvent) => {
180	      if (e.key === "Escape" && connectingSource !== null) {
181	        setConnectingSource(null);
182	        setAnnouncement("Connection cancelled.");
183	      }
184	    },
185	    [connectingSource],
186	  );
187	
188	  // Clear drag state when mouse released anywhere (including outside component)
189	  useEffect(() => {
190	    document.addEventListener("mouseup", handleGlobalMouseUp);
191	    return () => {
192	      document.removeEventListener("mouseup", handleGlobalMouseUp);
193	    };
194	  }, [handleGlobalMouseUp]);
195	
196	  return (
197	    <div
198	      ref={containerRef}
199	      data-testid="mod-matrix"
200	      onMouseUp={handleGlobalMouseUp}
201	      onKeyDown={handleKeyDown}
202	      style={{
203	        display: "flex",
204	        flexDirection: "column",
205	        gap: tokens.space[2],
206	        border: BORDER,
207	        padding: tokens.space[2],
208	        backgroundColor: tokens.color.gray900,
209	        fontFamily: tokens.font.mono,
210	        fontSize: tokens.text.sm,
211	        color: tokens.color.gray100,
212	        userSelect: "none",
213	      }}
214	    >
215	      <span
216	        style={{
217	          ...LABEL_STYLE,
218	          color: tokens.color.blue,
219	          fontSize: tokens.text.sm,
220	        }}
221	      >
222	        MOD MATRIX
223	      </span>
224	
225	      {/* Live region for screen reader announcements */}
226	      <div
227	        aria-live="polite"
228	        aria-atomic="true"
229	        className="sr-only"
230	        style={{
231	          position: "absolute",
232	          width: 1,
233	          height: 1,
234	          overflow: "hidden",
235	          clip: "rect(0,0,0,0)",
236	          whiteSpace: "nowrap",
237	        }}
238	      >
239	        {announcement}
240	      </div>
241	
242	      {/* Sources and Destinations side by side */}
243	      <div style={{ display: "flex", gap: tokens.space[4] }}>
244	        {/* Sources */}
245	        <div
246	          style={{
247	            display: "flex",
248	            flexDirection: "column",
249	            gap: tokens.space[1],
250	          }}
251	        >
252	          <span style={LABEL_STYLE}>SOURCES</span>
253	          {MOD_SOURCES.map((src) => (
254	            <div
255	              key={src}
256	              style={{
257	                display: "flex",
258	                alignItems: "center",
259	                gap: tokens.space[1],
260	              }}
261	            >
262	              <span
263	                style={{
264	                  ...LABEL_STYLE,
265	                  width: 80,
266	                  color:
267	                    activeSource === src
268	                      ? SOURCE_COLORS[src]
269	                      : tokens.color.gray300,
270	                }}
271	              >
272	                {MOD_SOURCE_LABELS[src]}
273	              </span>
274	              <Port
275	                testId={`src-port-${src}`}
276	                color={SOURCE_COLORS[src]}
277	                label={`Source: ${MOD_SOURCE_LABELS[src]}`}
278	                highlight={connectingSource === src}
279	                onMouseDown={() => {
280	                  handleSrcMouseDown(src);
281	                }}
282	                onKeyAction={() => {
283	                  handleSrcKeyAction(src);
284	                }}
285	              />
286	            </div>
287	          ))}
288	        </div>
289	
290	        {/* SVG cable visualization area */}
291	        <div style={{ position: "relative", width: 60, minHeight: 200 }}>
292	          <svg
293	            viewBox="0 0 60 200"
294	            preserveAspectRatio="none"
295	            style={{
296	              position: "absolute",
297	              top: 0,
298	              left: 0,
299	              width: "100%",
300	              height: "100%",
301	              pointerEvents: "none",
302	            }}
303	          >
304	            {routes.map((route) => {
305	              const srcIdx = MOD_SOURCES.indexOf(route.source);
306	              const destIdx = MOD_DESTINATIONS.indexOf(route.destination);
307	              const srcY = 20 + srcIdx * 22;
308	              const destY = 20 + destIdx * 22;
309	              return (
310	                <line
311	                  key={route.id}
312	                  data-testid={`cable-${route.source}-${route.destination}`}
313	                  x1={0}
314	                  y1={srcY}
315	                  x2={60}
316	                  y2={destY}
317	                  stroke={SOURCE_COLORS[route.source]}
318	                  strokeWidth={2}
319	                  strokeOpacity={0.7 + Math.abs(route.amount) * 0.3}
320	                />
321	              );
322	            })}
323	          </svg>
324	        </div>
325	
326	        {/* Destinations */}
327	        <div
328	          style={{
329	            display: "flex",
330	            flexDirection: "column",
331	            gap: tokens.space[1],
332	          }}
333	        >
334	          <span style={LABEL_STYLE}>DESTINATIONS</span>
335	          {MOD_DESTINATIONS.map((dest) => (
336	            <div
337	              key={dest}
338	              style={{
339	                display: "flex",
340	                alignItems: "center",
341	                gap: tokens.space[1],
342	              }}
343	            >
344	              <Port
345	                testId={`dest-port-${dest}`}
346	                color={
347	                  connectingSource !== null
348	                    ? tokens.color.white
349	                    : tokens.color.gray500
350	                }
351	                label={`Destination: ${MOD_DEST_LABELS[dest]}`}
352	                onMouseUp={() => {
353	                  handleDestMouseUp(dest);
354	                }}
355	                onKeyAction={() => {
356	                  handleDestKeyAction(dest);
357	                }}
358	              />
359	              <span style={{ ...LABEL_STYLE, width: 80 }}>
360	                {MOD_DEST_LABELS[dest]}
361	              </span>
362	            </div>
363	          ))}
364	        </div>
365	      </div>
366	
367	      {/* Active routes list with amount controls */}
368	      {routes.length > 0 && (
369	        <div
370	          style={{
371	            display: "flex",
372	            flexDirection: "column",
373	            gap: tokens.space[1],
374	            borderTop: BORDER,
375	            paddingTop: tokens.space[2],
376	          }}
377	        >
378	          <span style={LABEL_STYLE}>ROUTES</span>
379	          {routes.map((route) => (
380	            <div
381	              key={route.id}
382	              style={{
383	                display: "flex",
384	                alignItems: "center",
385	                gap: tokens.space[2],
386	                padding: `${String(tokens.space.half)}px 0`,
387	              }}
388	            >
389	              <span
390	                style={{
391	                  ...LABEL_STYLE,
392	                  color: SOURCE_COLORS[route.source],
393	                  width: 80,
394	                }}
395	              >
396	                {MOD_SOURCE_LABELS[route.source]}
397	              </span>
398	              <span style={{ ...LABEL_STYLE, color: tokens.color.gray500 }}>
399	                {">"}
400	              </span>
401	              <span style={{ ...LABEL_STYLE, width: 80 }}>
402	                {MOD_DEST_LABELS[route.destination]}
403	              </span>
404	              <input
405	                type="range"
406	                data-testid={`route-amount-${route.id}`}
407	                min={-1}
408	                max={1}
409	                step={0.01}
410	                value={route.amount}
411	                onChange={(e) => {
412	                  updateAmount(trackId, route.id, Number(e.target.value));
413	                }}
414	                style={{ width: 80, accentColor: SOURCE_COLORS[route.source] }}
415	              />
416	              <span style={{ ...LABEL_STYLE, width: 40, textAlign: "right" }}>
417	                {(route.amount * 100).toFixed(0)}%
418	              </span>
419	              <button
420	                data-testid={`route-bipolar-${route.id}`}
421	                aria-label={`Toggle bipolar mode for ${MOD_SOURCE_LABELS[route.source]} to ${MOD_DEST_LABELS[route.destination]}`}
422	                aria-pressed={route.bipolar}
423	                onClick={() => {
424	                  toggleBipolar(trackId, route.id);
425	                }}
426	                style={{
427	                  background: "none",
428	                  border: `${String(tokens.border.width)}px solid ${route.bipolar ? tokens.color.blue : tokens.color.gray700}`,
429	                  color: route.bipolar
430	                    ? tokens.color.blue
431	                    : tokens.color.gray500,
432	                  fontFamily: tokens.font.mono,
433	                  fontSize: tokens.text["2xs"],
434	                  cursor: "pointer",
435	                  padding: `${String(tokens.space.px)}px ${String(tokens.space[1] - 1)}px`,
436	                }}
437	              >
438	                {route.bipolar ? "BI" : "UNI"}
439	              </button>
440	              <button
441	                data-testid={`route-delete-${route.id}`}
442	                aria-label={`Remove route ${MOD_SOURCE_LABELS[route.source]} to ${MOD_DEST_LABELS[route.destination]}`}
443	                onClick={() => {
444	                  removeRoute(trackId, route.id);
445	                }}
446	                style={{
447	                  background: "none",
448	                  border: `${String(tokens.border.width)}px solid ${tokens.color.gray700}`,
449	                  color: tokens.color.gray500,
450	                  fontFamily: tokens.font.mono,
451	                  fontSize: tokens.text.xs,
452	                  cursor: "pointer",
453	                  padding: `${String(tokens.space.px)}px ${String(tokens.space[1])}px`,
454	                }}
455	              >
456	                X
457	              </button>
458	            </div>
459	          ))}
460	        </div>
461	      )}
462	    </div>
463	  );
464	}
