1	import { useState } from "react";
2	import { Spinner } from "./primitives/Spinner";
3	import styles from "./ClickToStart.module.css";
4	
5	export const ENGINE_TIMEOUT_MS = 30_000;
6	
7	type ClickToStartProps = {
8	  onStart: () => Promise<void>;
9	};
10	
11	export function ClickToStart({
12	  onStart,
13	}: ClickToStartProps): React.JSX.Element {
14	  const [loading, setLoading] = useState(false);
15	  const [error, setError] = useState<string | null>(null);
16	
17	  const handleClick = async (): Promise<void> => {
18	    setLoading(true);
19	    setError(null);
20	    try {
21	      await Promise.race([
22	        onStart(),
23	        new Promise<never>((_, reject) => {
24	          setTimeout(() => {
25	            reject(new Error("timeout"));
26	          }, ENGINE_TIMEOUT_MS);
27	        }),
28	      ]);
29	    } catch (e) {
30	      setLoading(false);
31	      const isTimeout = e instanceof Error && e.message === "timeout";
32	      setError(
33	        isTimeout
34	          ? "Audio engine timed out. Click to retry."
35	          : "Failed to start audio engine. Click to retry.",
36	      );
37	    }
38	  };
39	
40	  return (
41	    <button
42	      type="button"
43	      onClick={() => {
44	        void handleClick();
45	      }}
46	      disabled={loading}
47	      className={styles.overlay}
48	    >
49	      <div className={styles.content}>
50	        <p className={styles.title}>BRUTALWAV</p>
51	        {loading ? (
52	          <div className={styles.status}>
53	            <Spinner />
54	            <span>Starting audio engine...</span>
55	          </div>
56	        ) : error !== null ? (
57	          <p className={styles.error}>{error}</p>
58	        ) : (
59	          <p className={styles.hint}>Click to start audio engine</p>
60	        )}
61	      </div>
62	    </button>
63	  );
64	}
