1	/**
2	 * TR-808 Drum Machine panel.
3	 * Pad grid, step sequencer rows per instrument, per-instrument knobs,
4	 * pattern A/B selector, accent row, current step indicator.
5	 */
6	
7	import { useCallback, useRef, useState } from "react";
8	import { tokens } from "@ui/tokens/tokens";
9	import { StepButton } from "@ui/controls/StepButton";
10	import { DrumPad } from "@ui/controls/DrumPad";
11	import { DRUM_INSTRUMENTS, PARAM_RANGES } from "@audio/drum-machine/drum-types";
12	import type {
13	  DrumInstrumentId,
14	  DrumInstrumentParams,
15	  DrumPattern,
16	} from "@audio/drum-machine/drum-types";
17	
18	type DrumMachinePanelProps = {
19	  pattern: DrumPattern;
20	  currentStep: number;
21	  activePatternName: string;
22	  onToggleStep: (instrumentId: DrumInstrumentId, stepIndex: number) => void;
23	  onSetAccent: (stepIndex: number, accent: boolean) => void;
24	  onTriggerPad: (instrumentId: DrumInstrumentId) => void;
25	  onParamChange: (
26	    instrumentId: DrumInstrumentId,
27	    key: keyof DrumInstrumentParams,
28	    value: number,
29	  ) => void;
30	  onSwitchPattern: (name: string) => void;
31	  onClearPattern: () => void;
32	  params: Record<DrumInstrumentId, DrumInstrumentParams>;
33	};
34	
35	const BORDER = "var(--border)";
36	
37	const labelStyle: React.CSSProperties = {
38	  fontFamily: tokens.font.mono,
39	  fontSize: tokens.text.xs,
40	  color: tokens.color.gray300,
41	  textTransform: "uppercase",
42	  letterSpacing: "0.1em",
43	  width: 64,
44	  textAlign: "right",
45	  flexShrink: 0,
46	};
47	
48	function ParamKnob({
49	  label,
50	  value,
51	  min,
52	  max,
53	  step,
54	  onChange,
55	}: {
56	  label: string;
57	  value: number;
58	  min: number;
59	  max: number;
60	  step: number;
61	  onChange: (v: number) => void;
62	}): React.JSX.Element {
63	  return (
64	    <div
65	      style={{
66	        display: "flex",
67	        flexDirection: "column",
68	        alignItems: "center",
69	        gap: 1,
70	      }}
71	    >
72	      <span
73	        style={{
74	          fontFamily: tokens.font.mono,
75	          fontSize: tokens.text["2xs"],
76	          color: tokens.color.gray300,
77	        }}
78	      >
79	        {label}
80	      </span>
81	      <input
82	        type="range"
83	        min={min}
