1	import { useCallback, useRef, useEffect } from "react";
2	import styles from "./Fader.module.css";
3	
4	type FaderProps = {
5	  value: number;
6	  min: number;
7	  max: number;
8	  step?: number;
9	  onChange: (value: number) => void;
10	  label: string;
11	  height?: number;
12	  valueText?: string;
13	};
14	
15	function clamp(val: number, min: number, max: number): number {
16	  return Math.min(max, Math.max(min, val));
17	}
18	
19	export function Fader({
20	  value,
21	  min,
22	  max,
23	  step = 1,
24	  onChange,
25	  label,
26	  height = 128,
27	  valueText,
28	}: FaderProps): React.JSX.Element {
29	  const trackRef = useRef<HTMLDivElement>(null);
30	  const listenersRef = useRef<AbortController | null>(null);
31	
32	  const fraction = max === min ? 0 : (value - min) / (max - min);
33	
34	  // Cleanup drag listeners on unmount
35	  useEffect(() => {
36	    return (): void => {
37	      listenersRef.current?.abort();
38	    };
39	  }, []);
40	
41	  const handleKeyDown = useCallback(
42	    (e: React.KeyboardEvent): void => {
43	      let next: number | undefined;
44	
45	      switch (e.key) {
46	        case "ArrowUp":
47	          next = clamp(value + step, min, max);
48	          break;
49	        case "ArrowDown":
50	          next = clamp(value - step, min, max);
51	          break;
52	        case "PageUp":
53	          next = clamp(value + step * 10, min, max);
54	          break;
55	        case "PageDown":
56	          next = clamp(value - step * 10, min, max);
57	          break;
58	        case "Home":
59	          next = min;
60	          break;
61	        case "End":
62	          next = max;
63	          break;
64	        default:
65	          return;
66	      }
67	
68	      e.preventDefault();
69	      onChange(next);
70	    },
71	    [value, min, max, step, onChange],
72	  );
73	
74	  const valueFromY = useCallback(
75	    (clientY: number): number => {
76	      const track = trackRef.current;
77	      if (!track) return value;
78	      const rect = track.getBoundingClientRect();
79	      const pxFromBottom = rect.bottom - clientY;
80	      const ratio = pxFromBottom / rect.height;
81	      const raw = min + ratio * (max - min);
82	      return clamp(Math.round(raw / step) * step, min, max);
83	    },
84	    [value, min, max, step],
85	  );
86	
87	  const handlePointerDown = useCallback(
88	    (e: React.PointerEvent): void => {
89	      e.preventDefault();
90	      const target = e.target as HTMLElement;
91	      if (typeof target.setPointerCapture === "function") {
92	        target.setPointerCapture(e.pointerId);
93	      }
94	
95	      listenersRef.current?.abort();
96	      const controller = new AbortController();
97	      listenersRef.current = controller;
98	
99	      document.addEventListener(
100	        "pointermove",
101	        (ev: PointerEvent) => {
102	          onChange(valueFromY(ev.clientY));
103	        },
104	        { signal: controller.signal },
105	      );
106	      document.addEventListener(
107	        "pointerup",
108	        () => {
109	          controller.abort();
110	        },
111	        { signal: controller.signal },
112	      );
113	    },
114	    [onChange, valueFromY],
115	  );
116	
117	  return (
118	    <div
119	      className={styles["container"]}
120	      role="slider"
121	      tabIndex={0}
122	      aria-valuemin={min}
123	      aria-valuemax={max}
124	      aria-valuenow={value}
125	      aria-valuetext={valueText}
126	      aria-orientation="vertical"
127	      aria-label={label}
128	      onKeyDown={handleKeyDown}
129	    >
130	      <div
131	        ref={trackRef}
132	        className={styles["track"]}
133	        style={{ height: `${String(height)}px` }}
134	      >
135	        <div
136	          className={styles["active"]}
137	          style={{ height: `${String(fraction * 100)}%` }}
138	        />
139	        <div
140	          className={styles["thumb"]}
141	          style={{ bottom: `${String(fraction * 100)}%` }}
142	          onPointerDown={handlePointerDown}
143	        />
144	      </div>
145	      <span className={styles["label"]}>{label}</span>
146	    </div>
147	  );
148	}
