1	import { useRef, useEffect, useCallback } from "react";
2	import { tokens } from "../tokens/tokens";
3	import { useReducedMotion } from "../hooks/useReducedMotion";
4	
5	type VuMeterProps = {
6	  level: number;
7	  peak?: number;
8	  clip?: boolean;
9	  width?: number;
10	  height?: number;
11	};
12	
13	const DEFAULT_WIDTH = 12;
14	const DEFAULT_HEIGHT = 128;
15	const PEAK_DECAY_RATE = 0.005;
16	const CLIP_INDICATOR_SIZE = 4;
17	const CLIP_PULSE_SPEED = 4; // cycles per second
18	
19	function getLevelColor(normalizedY: number): string {
20	  if (normalizedY > 0.9) return tokens.color.red;
21	  if (normalizedY > 0.7) return tokens.color.amber;
22	  return tokens.color.green;
23	}
24	
25	function buildAriaLabel(level: number, clip: boolean): string {
26	  const pct = Math.round(level * 100);
27	  return clip
28	    ? `Audio level: ${String(pct)}% (clipping)`
29	    : `Audio level: ${String(pct)}%`;
30	}
31	
32	export function VuMeter({
33	  level: rawLevel,
34	  peak,
35	  clip,
36	  width = DEFAULT_WIDTH,
37	  height = DEFAULT_HEIGHT,
38	}: VuMeterProps): React.JSX.Element {
39	  const canvasRef = useRef<HTMLCanvasElement>(null);
40	  const peakHoldRef = useRef(peak ?? 0);
41	  const rafRef = useRef(0);
42	  const animatingRef = useRef(false);
43	  const reducedMotion = useReducedMotion();
44	
45	  const level = Math.min(1, Math.max(0, rawLevel));
46	
47	  const draw = useCallback(
48	    (ctx: CanvasRenderingContext2D, time = 0): void => {
49	      const w = width;
50	      const h = height;
51	
52	      // Background
53	      ctx.fillStyle = tokens.color.black;
54	      ctx.fillRect(0, 0, w, h);
55	
56	      // Level bar (drawn from bottom up)
57	      const barHeight = level * h;
58	      const barTop = h - barHeight;
59	
60	      for (let y = barTop; y < h; y++) {
61	        const normalizedY = 1 - y / h;
62	        ctx.fillStyle = getLevelColor(normalizedY);
63	        ctx.fillRect(0, y, w, 1);
64	      }
65	
66	      // Peak hold line with ease-out decay
67	      const currentPeak = peakHoldRef.current;
68	      if (currentPeak > 0) {
69	        const peakY = h - currentPeak * h;
70	        ctx.strokeStyle = tokens.color.white;
71	        ctx.lineWidth = 1;
72	        ctx.beginPath();
73	        ctx.moveTo(0, peakY);
74	        ctx.lineTo(w, peakY);
75	        ctx.stroke();
76	      }
77	
78	      // Clip indicator with pulse animation
79	      if (clip === true) {
80	        const pulse = reducedMotion
81	          ? 1
82	          : 0.5 + 0.5 * Math.sin(time * CLIP_PULSE_SPEED * 2 * Math.PI);
83	        const size = CLIP_INDICATOR_SIZE + (reducedMotion ? 0 : pulse * 2);
84	        ctx.globalAlpha = 0.4 + 0.6 * pulse;
85	        ctx.fillStyle = tokens.color.red;
86	        ctx.fillRect((w - size) / 2, 1, size, size);
87	        ctx.globalAlpha = 1;
88	      }
89	    },
90	    [level, clip, width, height, reducedMotion],
91	  );
92	
93	  useEffect(() => {
94	    const canvas = canvasRef.current;
95	    if (canvas === null) return;
96	    const ctx = canvas.getContext("2d");
97	    if (ctx === null) return;
98	
99	    // Update peak hold from prop or current level
100	    if (peak !== undefined) {
101	      peakHoldRef.current = peak;
102	    } else if (level > peakHoldRef.current) {
103	      peakHoldRef.current = level;
104	    }
105	
106	    draw(ctx);
107	
108	    // Animate when peak is decaying or clip is pulsing
109	    const needsAnimation =
110	      (peak === undefined && peakHoldRef.current > 0) ||
111	      (clip === true && !reducedMotion);
112	
113	    if (needsAnimation && !animatingRef.current) {
114	      animatingRef.current = true;
115	      const startTime = performance.now();
116	      const animate = (): void => {
117	        const elapsed = (performance.now() - startTime) / 1000;
118	
119	        // Ease-out peak decay: rate slows as peak approaches 0
120	        if (peak === undefined && peakHoldRef.current > 0) {
121	          const decayRate = PEAK_DECAY_RATE * (0.3 + 0.7 * peakHoldRef.current);
122	          peakHoldRef.current = Math.max(0, peakHoldRef.current - decayRate);
123	        }
124	
125	        draw(ctx, elapsed);
126	
127	        const stillDecaying = peak === undefined && peakHoldRef.current > 0;
128	        const stillClipping = clip === true && !reducedMotion;
129	
130	        if (stillDecaying || stillClipping) {
131	          rafRef.current = requestAnimationFrame(animate);
132	        } else {
133	          animatingRef.current = false;
134	        }
135	      };
136	      rafRef.current = requestAnimationFrame(animate);
137	    }
138	
139	    return (): void => {
140	      cancelAnimationFrame(rafRef.current);
141	      animatingRef.current = false;
142	    };
143	  }, [level, peak, clip, draw, reducedMotion]);
144	
145	  const isClipping = clip === true;
146	
147	  return (
148	    <canvas
149	      ref={canvasRef}
150	      role="img"
151	      aria-label={buildAriaLabel(level, isClipping)}
152	      width={width}
153	      height={height}
154	    />
155	  );
156	}
