1	/**
2	 * Effects rack for a single track.
3	 * Shows insert chain with add/remove/bypass controls.
4	 */
5	
6	import { useState, useCallback } from "react";
7	import { useEffectsStore } from "@state/effects";
8	import { useEffectsBridgeContext } from "@audio/effects/EffectsBridgeProvider";
9	import { tokens } from "@ui/tokens/tokens";
10	import { EffectPanel } from "./EffectPanel";
11	import { UndoToast, type UndoToastState } from "@ui/primitives/UndoToast";
12	import type { EffectSlotState } from "@state/effects/types";
13	
14	const EMPTY_SLOTS: readonly never[] = [];
15	
16	// Reverb A/B: swap between convolution and algorithmic reverb
17	const REVERB_SWAP: Record<string, string> = {
18	  reverb: "freeverb",
19	  freeverb: "reverb",
20	};
21	
22	type EffectsRackProps = {
23	  trackId: string;
24	};
25	
26	export function EffectsRack({ trackId }: EffectsRackProps): React.JSX.Element {
27	  const { registry } = useEffectsBridgeContext();
28	  const availableEffects = registry.getAll();
29	
30	  const slots = useEffectsStore((s) => s.trackEffects[trackId] ?? EMPTY_SLOTS);
31	  const addEffect = useEffectsStore((s) => s.addEffect);
32	  const removeEffect = useEffectsStore((s) => s.removeEffect);
33	  const updateEffectParam = useEffectsStore((s) => s.updateEffectParam);
34	  const toggleBypass = useEffectsStore((s) => s.toggleBypass);
35	  const swapEffectType = useEffectsStore((s) => s.swapEffectType);
36	
37	  const [showSelector, setShowSelector] = useState(false);
38	  const [undoPending, setUndoPending] = useState<UndoToastState | null>(null);
39	
40	  const handleRemove = useCallback(
41	    (slot: EffectSlotState) => {
42	      const snapshot = { ...slot, params: { ...slot.params } };
43	      const factory = registry.get(slot.typeId);
44	      const name = factory?.definition.name ?? slot.typeId;
45	      removeEffect(trackId, slot.id);
46	      setUndoPending({
47	        message: `Removed ${name}.`,
48	        onUndo: () => {
49	          addEffect(trackId, snapshot);
50	          setUndoPending(null);
51	        },
52	      });
53	    },
54	    [trackId, removeEffect, addEffect, registry],
55	  );
56	
57	  const handleUndoExpired = useCallback(() => {
58	    setUndoPending(null);
59	  }, []);
60	
61	  const handleSwapReverb = useCallback(
62	    (
63	      slotId: string,
64	      currentTypeId: string,
65	      currentParams: Record<string, number>,
66	    ) => {
67	      const targetTypeId = REVERB_SWAP[currentTypeId];
68	      if (targetTypeId === undefined || targetTypeId === "") return;
69	      const targetFactory = registry.get(targetTypeId);
70	      if (!targetFactory) return;
71	      const newParams: Record<string, number> = {};
72	      for (const p of targetFactory.definition.parameters) {
73	        newParams[p.key] = p.default;
74	      }
75	      // Preserve mix level for meaningful A/B comparison
76	      const currentMix = currentParams.mix;
77	      if (currentMix !== undefined) {
78	        newParams.mix = currentMix;
79	      }
80	      swapEffectType(trackId, slotId, targetTypeId, newParams);
81	    },
82	    [trackId, swapEffectType, registry],
83	  );
84	
85	  const handleAdd = useCallback(
86	    (typeId: string) => {
87	      const factory = registry.get(typeId);
88	      if (!factory) return;
89	
90	      const id = `${typeId}-${crypto.randomUUID().slice(0, 8)}`;
91	      const params: Record<string, number> = {};
92	      for (const p of factory.definition.parameters) {
93	        params[p.key] = p.default;
94	      }
95	
96	      addEffect(trackId, { id, typeId, bypassed: false, params });
97	      setShowSelector(false);
98	    },
99	    [trackId, addEffect, registry],
100	  );
101	
102	  return (
103	    <div
104	      data-testid="effects-rack"
105	      style={{
106	        display: "flex",
107	        flexDirection: "column",
108	        gap: tokens.space[1],
109	        padding: tokens.space[2],
110	        borderTop: "2px solid var(--color-gray-700)",
111	        backgroundColor: tokens.color.gray900,
112	        minHeight: 40,
113	      }}
114	    >
115	      {slots.map((slot) => {
116	        const factory = registry.get(slot.typeId);
117	        if (!factory) return null;
118	
119	        const isReverbType = slot.typeId in REVERB_SWAP;
120	        const swapTarget = REVERB_SWAP[slot.typeId];
121	        const swapTargetFactory =
122	          swapTarget !== undefined && swapTarget !== ""
123	            ? registry.get(swapTarget)
124	            : undefined;
125	
126	        return (
127	          <EffectPanel
128	            key={slot.id}
129	            definition={factory.definition}
130	            params={slot.params}
131	            bypassed={slot.bypassed}
132	            onParamChange={(key, value) => {
133	              updateEffectParam(trackId, slot.id, key, value);
134	            }}
135	            onBypassToggle={() => {
136	              toggleBypass(trackId, slot.id);
137	            }}
138	            onRemove={() => {
139	              handleRemove(slot);
140	            }}
141	            onSwapType={
142	              isReverbType
143	                ? () => {
144	                    handleSwapReverb(slot.id, slot.typeId, slot.params);
145	                  }
146	                : undefined
147	            }
148	            swapLabel={swapTargetFactory?.definition.name}
149	          />
150	        );
151	      })}
152	
153	      {showSelector ? (
154	        <div
155	          style={{
156	            display: "flex",
157	            flexWrap: "wrap",
158	            gap: tokens.space[1],
159	          }}
160	        >
161	          {availableEffects.map((f) => (
162	            <button
163	              key={f.definition.id}
164	              type="button"
165	              aria-label={`Add ${f.definition.name} effect`}
166	              onClick={() => {
167	                handleAdd(f.definition.id);
168	              }}
169	              style={{
170	                fontFamily: tokens.font.mono,
171	                fontSize: tokens.text.xs,
172	                border: "2px solid var(--color-gray-700)",
173	                background: "transparent",
174	                color: tokens.color.white,
175	                cursor: "pointer",
176	                padding: `${String(tokens.space[1])}px ${String(tokens.space[2])}px`,
177	              }}
178	            >
179	              {f.definition.name}
180	            </button>
181	          ))}
182	          <button
183	            type="button"
184	            onClick={() => {
185	              setShowSelector(false);
186	            }}
187	            style={{
188	              fontFamily: tokens.font.mono,
189	              fontSize: tokens.text.xs,
190	              border: "2px solid var(--color-gray-700)",
191	              background: "transparent",
192	              color: tokens.color.gray300,
193	              cursor: "pointer",
194	              padding: "4px 8px",
195	            }}
196	          >
197	            Cancel
198	          </button>
199	        </div>
200	      ) : (
201	        <button
202	          type="button"
203	          aria-label="Add effect"
204	          onClick={() => {
205	            setShowSelector(true);
206	          }}
207	          style={{
208	            fontFamily: tokens.font.mono,
209	            fontSize: tokens.text.xs,
210	            border: "2px solid var(--color-gray-700)",
211	            background: "transparent",
212	            color: tokens.color.green,
213	            cursor: "pointer",
214	            padding: "4px 8px",
215	            alignSelf: "flex-start",
216	          }}
217	        >
218	          + INSERT
219	        </button>
220	      )}
221	      <UndoToast pending={undoPending} onExpired={handleUndoExpired} />
222	    </div>
223	  );
224	}
