190	    document.addEventListener("mouseup", handleGlobalMouseUp);
191	    return () => {
192	      document.removeEventListener("mouseup", handleGlobalMouseUp);
193	    };
194	  }, [handleGlobalMouseUp]);
195	
196	  return (
197	    <div
