1	/**
2	 * TR-808 Drum Machine panel.
3	 * Pad grid, step sequencer rows per instrument, per-instrument knobs,
4	 * pattern A/B selector, accent row, current step indicator.
5	 */
6	
7	import { useCallback, useRef, useState } from "react";
8	import { tokens } from "@ui/tokens/tokens";
9	import { StepButton } from "@ui/controls/StepButton";
10	import { DrumPad } from "@ui/controls/DrumPad";
11	import { DRUM_INSTRUMENTS, PARAM_RANGES } from "@audio/drum-machine/drum-types";
12	import type {
13	  DrumInstrumentId,
14	  DrumInstrumentParams,
15	  DrumPattern,
16	} from "@audio/drum-machine/drum-types";
17	
18	type DrumMachinePanelProps = {
19	  pattern: DrumPattern;
20	  currentStep: number;
21	  activePatternName: string;
22	  onToggleStep: (instrumentId: DrumInstrumentId, stepIndex: number) => void;
23	  onSetAccent: (stepIndex: number, accent: boolean) => void;
24	  onTriggerPad: (instrumentId: DrumInstrumentId) => void;
25	  onParamChange: (
26	    instrumentId: DrumInstrumentId,
27	    key: keyof DrumInstrumentParams,
28	    value: number,
29	  ) => void;
30	  onSwitchPattern: (name: string) => void;
31	  onClearPattern: () => void;
32	  params: Record<DrumInstrumentId, DrumInstrumentParams>;
33	};
34	
35	const BORDER = "var(--border)";
36	
37	const labelStyle: React.CSSProperties = {
38	  fontFamily: tokens.font.mono,
39	  fontSize: tokens.text.xs,
40	  color: tokens.color.gray300,
41	  textTransform: "uppercase",
42	  letterSpacing: "0.1em",
43	  width: 64,
44	  textAlign: "right",
45	  flexShrink: 0,
46	};
47	
48	function ParamKnob({
49	  label,
50	  value,
51	  min,
52	  max,
53	  step,
54	  onChange,
55	}: {
56	  label: string;
57	  value: number;
58	  min: number;
59	  max: number;
60	  step: number;
61	  onChange: (v: number) => void;
62	}): React.JSX.Element {
63	  return (
64	    <div
65	      style={{
66	        display: "flex",
67	        flexDirection: "column",
68	        alignItems: "center",
69	        gap: 1,
70	      }}
71	    >
72	      <span
73	        style={{
74	          fontFamily: tokens.font.mono,
75	          fontSize: tokens.text["2xs"],
76	          color: tokens.color.gray300,
77	        }}
78	      >
79	        {label}
80	      </span>
81	      <input
82	        type="range"
83	        min={min}
84	        max={max}
85	        step={step}
86	        value={value}
87	        onChange={(e) => {
88	          onChange(Number(e.target.value));
89	        }}
90	        style={{ width: 48, accentColor: tokens.color.amber }}
91	        aria-label={label}
92	      />
93	    </div>
94	  );
95	}
96	
97	function InstrumentRow({
98	  instrumentId,
99	  instrumentLabel,
100	  steps,
101	  currentStep,
102	  params,
103	  onToggle,
104	  onTriggerPad,
105	  onParamChange,
106	}: {
107	  instrumentId: DrumInstrumentId;
108	  instrumentLabel: string;
109	  steps: DrumPattern["steps"];
110	  currentStep: number;
111	  params: DrumInstrumentParams;
112	  onToggle: (step: number) => void;
113	  onTriggerPad: () => void;
114	  onParamChange: (key: keyof DrumInstrumentParams, value: number) => void;
115	}): React.JSX.Element {
116	  const [focusedStep, setFocusedStep] = useState(0);
117	  const stepRefs = useRef<(HTMLButtonElement | null)[]>([]);
118	
119	  const handleArrowNav = useCallback(
120	    (index: number, direction: -1 | 1) => {
121	      const next = index + direction;
122	      if (next >= 0 && next < steps.length) {
123	        setFocusedStep(next);
124	        stepRefs.current[next]?.focus();
125	      }
126	    },
127	    [steps.length],
128	  );
129	
130	  return (
131	    <div
132	      data-testid={`instrument-row-${instrumentId}`}
133	      role="group"
134	      aria-label={`${instrumentLabel} steps`}
135	      style={{ display: "flex", alignItems: "center", gap: tokens.space[2] }}
136	    >
137	      <DrumPad label={instrumentLabel} onTrigger={onTriggerPad} size={32} />
138	      <span style={labelStyle}>{instrumentId.toUpperCase()}</span>
139	      <div style={{ display: "flex", gap: 2 }}>
140	        {steps.map((step, i) => (
141	          <StepButton
142	            key={i}
143	            ref={(el) => {
144	              stepRefs.current[i] = el;
145	            }}
146	            active={step.triggers[instrumentId]}
147	            current={i === currentStep}
148	            onToggle={() => {
149	              onToggle(i);
150	            }}
151	            index={i}
152	            tabIndex={i === focusedStep ? 0 : -1}
153	            onArrowNav={(dir) => {
154	              handleArrowNav(i, dir);
155	            }}
156	          />
157	        ))}
158	      </div>
159	      <div
160	        style={{
161	          display: "flex",
162	          gap: tokens.space[1],
163	          marginLeft: tokens.space[2],
164	        }}
165	      >
166	        <ParamKnob
167	          label="Tone"
168	          value={params.tone}
169	          min={PARAM_RANGES.tone.min}
170	          max={PARAM_RANGES.tone.max}
171	          step={100}
172	          onChange={(v) => {
173	            onParamChange("tone", v);
174	          }}
175	        />
176	        <ParamKnob
177	          label="Decay"
178	          value={params.decay}
179	          min={PARAM_RANGES.decay.min}
180	          max={PARAM_RANGES.decay.max}
181	          step={0.01}
182	          onChange={(v) => {
183	            onParamChange("decay", v);
184	          }}
185	        />
186	        <ParamKnob
187	          label="Tune"
188	          value={params.tune}
189	          min={PARAM_RANGES.tune.min}
190	          max={PARAM_RANGES.tune.max}
191	          step={0.01}
192	          onChange={(v) => {
193	            onParamChange("tune", v);
194	          }}
195	        />
196	        <ParamKnob
197	          label="Vol"
198	          value={params.volume}
199	          min={PARAM_RANGES.volume.min}
200	          max={PARAM_RANGES.volume.max}
201	          step={0.01}
202	          onChange={(v) => {
203	            onParamChange("volume", v);
204	          }}
205	        />
206	      </div>
207	    </div>
208	  );
209	}
210	
211	function AccentRow({
212	  steps,
213	  currentStep,
214	  onSetAccent,
215	}: {
216	  steps: DrumPattern["steps"];
217	  currentStep: number;
218	  onSetAccent: (stepIndex: number, accent: boolean) => void;
219	}): React.JSX.Element {
220	  return (
221	    <div
222	      data-testid="accent-row"
223	      style={{ display: "flex", alignItems: "center", gap: tokens.space[2] }}
224	    >
225	      <div style={{ width: 32 }} />
226	      <span style={labelStyle}>ACC</span>
227	      <div style={{ display: "flex", gap: 2 }}>
228	        {steps.map((step, i) => (
229	          <button
230	            key={i}
231	            type="button"
232	            aria-label={`Accent ${String(i + 1)}`}
233	            aria-pressed={step.accent}
234	            onClick={() => {
235	              onSetAccent(i, !step.accent);
236	            }}
237	            style={{
238	              display: "inline-flex",
239	              alignItems: "center",
240	              justifyContent: "center",
241	              width: 24,
242	              height: 12,
243	              padding: 0,
244	              border: BORDER,
245	              borderRadius: 0,
246	              background: step.accent
247	                ? tokens.color.pink
248	                : tokens.color.gray900,
249	              cursor: "pointer",
250	              borderColor: i === currentStep ? tokens.color.white : undefined,
251	            }}
252	          />
253	        ))}
254	      </div>
255	    </div>
256	  );
257	}
258	
259	export function DrumMachinePanel({
260	  pattern,
261	  currentStep,
262	  activePatternName,
263	  onToggleStep,
264	  onSetAccent,
265	  onTriggerPad,
266	  onParamChange,
267	  onSwitchPattern,
268	  onClearPattern,
269	  params,
270	}: DrumMachinePanelProps): React.JSX.Element {
271	  return (
272	    <div
273	      data-testid="drum-machine-panel"
274	      style={{
275	        display: "flex",
276	        flexDirection: "column",
277	        gap: tokens.space[1],
278	        padding: tokens.space[2],
279	        backgroundColor: tokens.color.gray900,
280	        fontFamily: tokens.font.mono,
281	        fontSize: tokens.text.sm,
282	        color: tokens.color.gray100,
283	        overflow: "auto",
284	      }}
285	    >
286	      {/* Header: title + pattern buttons */}
287	      <div
288	        style={{
289	          display: "flex",
290	          alignItems: "center",
291	          gap: tokens.space[2],
292	          borderBottom: BORDER,
293	          paddingBottom: tokens.space[1],
294	        }}
295	      >
